import{_ as i,c as a,o as n,ah as l}from"./chunks/framework.DwHsq7Fg.js";const g=JSON.parse('{"title":"Основы Docker: Логирование","description":"","frontmatter":{},"headers":[],"relativePath":"basic_docker/docker_logging.md","filePath":"basic_docker/docker_logging.md"}'),e={name:"basic_docker/docker_logging.md"};function t(h,s,k,p,o,r){return n(),a("div",null,s[0]||(s[0]=[l(`<h1 id="основы-docker-логирование" tabindex="-1">Основы Docker: Логирование <a class="header-anchor" href="#основы-docker-логирование" aria-label="Permalink to “Основы Docker: Логирование”">​</a></h1><p>Docker поддерживает несколько <strong>драйверов логирования (logging drivers)</strong>, которые используются для управления тем, как Docker собирает и хранит логи контейнеров. Вы можете настроить драйвер логирования по умолчанию для Docker Daemon или указать драйвер для каждого контейнера при его запуске.</p><h2 id="драиверы-логирования-docker" tabindex="-1">Драйверы логирования Docker <a class="header-anchor" href="#драиверы-логирования-docker" aria-label="Permalink to “Драйверы логирования Docker”">​</a></h2><p>Вот некоторые из наиболее часто используемых драйверов логирования:</p><ul><li><p><strong><code>json-file</code> (по умолчанию):</strong> Логи контейнеров записываются в JSON-файлы, расположенные на хост-машине в директории <code>/var/lib/docker/containers/&lt;container_id&gt;</code>. Каждый файл содержит метаданные и JSON-объект для каждой записи лога. Этот драйвер является драйвером по умолчанию.</p></li><li><p><strong><code>fluentd</code>:</strong> Перенаправляет логи контейнеров на сервер Fluentd. Fluentd — это open-source сборщик данных логов, который позволяет агрегировать и перенаправлять логи в различные бэкенды.</p></li><li><p><strong><code>syslog</code>:</strong> Перенаправляет логи контейнеров в системный журнал хост-машины (syslog).</p></li><li><p><strong><code>journald</code>:</strong> Использует системный журнал systemd (journald) для хранения и управления логами контейнеров (доступно только на системах с systemd).</p></li><li><p><strong><code>gelf</code> (Graylog Extended Log Format):</strong> Отправляет логи на сервер Graylog или другой сервер, поддерживающий формат GELF.</p></li><li><p><strong><code>awslogs</code>:</strong> Отправляет логи в AWS CloudWatch Logs.</p></li><li><p><strong><code>gcplogs</code>:</strong> Отправляет логи в Google Cloud Logging (ранее Stackdriver Logging).</p></li><li><p><strong><code>splunk</code>:</strong> Отправляет логи на сервер Splunk.</p></li><li><p><strong><code>none</code>:</strong> Отключает логирование для контейнера.</p></li></ul><h2 id="настроика-драивера-логирования-по-умолчанию" tabindex="-1">Настройка драйвера логирования по умолчанию <a class="header-anchor" href="#настроика-драивера-логирования-по-умолчанию" aria-label="Permalink to “Настройка драйвера логирования по умолчанию”">​</a></h2><p>Вы можете настроить драйвер логирования по умолчанию для Docker Daemon, отредактировав файл конфигурации Docker (<code>/etc/docker/daemon.json</code> на Linux).</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;log-driver&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;fluentd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;log-opts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;fluentd-address&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;192.168.1.10:2422&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;tag&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;{{.Name}}&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>После изменения файла <code>daemon.json</code> необходимо перезапустить Docker Daemon (<code>sudo systemctl restart docker</code>).</p><h2 id="настроика-драивера-логирования-для-контеинера" tabindex="-1">Настройка драйвера логирования для контейнера <a class="header-anchor" href="#настроика-драивера-логирования-для-контеинера" aria-label="Permalink to “Настройка драйвера логирования для контейнера”">​</a></h2><p>Вы можете указать драйвер логирования для отдельного контейнера при его запуске с помощью флага <code>--log-driver</code> команды <code>docker run</code>. Дополнительные опции для драйвера можно передать с помощью флага <code>--log-opt</code>.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-container</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> syslog</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-opt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> syslog-address=192.168.1.20:514</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-image</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> another-container</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json-file</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-opt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> max-size=10m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-opt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> max-file=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-another-image</span></span></code></pre></div><p>В первом примере используется драйвер <code>syslog</code> с указанием адреса syslog-сервера. Во втором примере используется драйвер <code>json-file</code> с ограничением размера файла лога и количества ротируемых файлов.</p><h2 id="просмотр-логов-контеинера-docker-logs" tabindex="-1">Просмотр логов контейнера (<code>docker logs</code>) <a class="header-anchor" href="#просмотр-логов-контеинера-docker-logs" aria-label="Permalink to “Просмотр логов контейнера (docker logs)”">​</a></h2><p>Команда <code>docker logs</code> используется для просмотра логов контейнера, независимо от используемого драйвера логирования (Docker Daemon сам извлекает логи, используя настроенный драйвер).</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container_id_or_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container_id_or_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Следить за логами в реальном времени (как tail -f)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --since</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;10m&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container_id_or_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Логи за последние 10 минут</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --until</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2023-10-27T10:00:00Z&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container_id_or_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Логи до указанного времени</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --timestamps</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container_id_or_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Добавить временные метки к логам</span></span></code></pre></div><h2 id="управление-размером-логов-json-file" tabindex="-1">Управление размером логов (<code>json-file</code>) <a class="header-anchor" href="#управление-размером-логов-json-file" aria-label="Permalink to “Управление размером логов (json-file)”">​</a></h2><p>Для драйвера <code>json-file</code> важно настроить ротацию логов, чтобы предотвратить заполнение дискового пространства большими файлами логов. Это можно сделать с помощью опций <code>--log-opt max-size</code> (максимальный размер файла лога) и <code>--log-opt max-file</code> (максимальное количество ротируемых файлов).</p><p>Пример в <code>docker run</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-web</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json-file</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-opt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> max-size=20m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-opt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> max-file=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:latest</span></span></code></pre></div><p>Аналогично в <code>docker-compose.yml</code>:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;3.9&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  web</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nginx:latest</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    logging</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      driver</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;json-file&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      options</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        max-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;20m&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        max-file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;5&quot;</span></span></code></pre></div><h2 id="лучшие-практики-логирования-docker" tabindex="-1">Лучшие практики логирования Docker <a class="header-anchor" href="#лучшие-практики-логирования-docker" aria-label="Permalink to “Лучшие практики логирования Docker”">​</a></h2><ul><li><strong>Используйте структурированные логи:</strong> Форматируйте логи в структурированном формате (например, JSON), чтобы их было легче парсить и анализировать с помощью инструментов обработки логов. Многие библиотеки логирования приложений поддерживают структурированный вывод.</li><li><strong>Централизованное логирование:</strong> Настройте перенаправление логов в централизованную систему управления логами (например, Elasticsearch, Graylog, Splunk, CloudWatch Logs, Google Cloud Logging) для агрегации, поиска, анализа и хранения логов из всех ваших контейнеров и хостов.</li><li><strong>Использование таймзон UTC:</strong> Согласуйте использование часового пояса UTC для всех логов, чтобы избежать проблем с различиями во времени при анализе.</li><li><strong>Включение достаточной информации:</strong> Логи должны содержать достаточно информации для диагностики проблем (например, временные метки, уровень логирования, источник, сообщение).</li><li><strong>Управление размером логов:</strong> Настройте ротацию логов, чтобы предотвратить переполнение диска.</li><li><strong>Безопасность логов:</strong> Защитите доступ к файлам логов и централизованной системе логирования.</li><li><strong>Использование уровней логирования:</strong> Применяйте различные уровни логирования (например, DEBUG, INFO, WARNING, ERROR, CRITICAL) для контроля объема генерируемых логов в зависимости от среды (разработка, production).</li><li><strong>Correlation ID:</strong> В распределенных системах включайте Correlation ID в логи, чтобы отслеживать запросы через несколько сервисов.</li><li><strong>Health Checks:</strong> Используйте health checks Docker и оркестраторов для отслеживания состояния приложений, и логи могут помочь в диагностике причин сбоев health checks.</li></ul><p>Правильно настроенное логирование является неотъемлемой частью эксплуатации контейнеризованных приложений. Оно обеспечивает видимость работы приложений, упрощает диагностику проблем и помогает в обеспечении стабильности и надежности системы. Выбор драйвера логирования и системы централизованного хранения и анализа логов зависит от ваших требований и инфраструктуры.</p>`,25)]))}const c=i(e,[["render",t]]);export{g as __pageData,c as default};
